queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?casename ?trialtype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTrials ?child ; p:hasCourts_Reporters ?parent . } GROUP BY ?child }
  ?child p:caseName ?casename .
  ?child p:trialType ?trialtype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Courts_Reporters } }
  FILTER(?nf = ?total)
}

